        id: 107,
        title: "ಉಡುರಾಜಮೌಳಿ ವಿನುತನೆ",
        dasaru: "ಜಗನ್ನಾಥ ದಾಸರು",
        god : "1. ಹರಿಪರ ಸ್ತೋತ್ರಗಳು",
